// Dimensiones del tablero (parametrizadas)
const BOARD_COLS = 15;
const BOARD_ROWS = 15;

// ============================================================
// v0.38: Editor de cartas con persistencia localStorage
// ============================================================
const EDITOR_STORAGE_KEY = 'starcity_card_overrides';
// Snapshot del valor ORIGINAL de cada carta (para resetear)
const CARD_ORIGINALS = {};
CARDS.forEach(function(c) {
  CARD_ORIGINALS[c.name] = {
    hp: c.hp, cost: c.cost, def: c.def, paT: c.paT
  };
});

function loadCardOverrides() {
  try {
    const raw = localStorage.getItem(EDITOR_STORAGE_KEY);
    if (!raw) return {};
    return JSON.parse(raw) || {};
  } catch (e) {
    console.warn('Editor: error al cargar overrides:', e);
    return {};
  }
}

function saveCardOverrides(overrides) {
  try {
    localStorage.setItem(EDITOR_STORAGE_KEY, JSON.stringify(overrides));
    return true;
  } catch (e) {
    console.warn('Editor: error al guardar:', e);
    return false;
  }
}

// Aplica los overrides actuales al array CARDS y a TODOS los mazos.
// Solo afecta a Unidades (hp, cost, def) y Estructuras + Castillo (hp, cost, paT).
function applyCardOverridesNow() {
  const overrides = loadCardOverrides();
  function applyToCard(c) {
    const o = overrides[c.name];
    if (!o) return;
    if (c.type === 'Unidad') {
      if (typeof o.hp === 'number') c.hp = o.hp;
      if (typeof o.cost === 'number') c.cost = o.cost;
      if (typeof o.def === 'number') c.def = o.def;
    } else if (c.type === 'Estructura' || c.type === 'Estructura Principal') {
      if (typeof o.hp === 'number') c.hp = o.hp;
      if (typeof o.cost === 'number') c.cost = o.cost;
      if (typeof o.paT === 'number') c.paT = o.paT;
    }
  }
  CARDS.forEach(applyToCard);
  [DECK_J1, DECK_J2].forEach(function(d) {
    d.forEach(applyToCard);
  });
}

// Aplicar overrides ahora (en cuanto carga el sandbox). Mazos y CARDS quedan listos.
applyCardOverridesNow();

// === UI del editor ===
function openEditor() {
  document.getElementById('editor-overlay').classList.add('show');
  renderEditorTab('unidades');
}

function closeEditor() {
  document.getElementById('editor-overlay').classList.remove('show');
}

let _editorCurrentTab = 'unidades';
function renderEditorTab(tab) {
  _editorCurrentTab = tab;
  // Toggle tabs visualmente
  document.querySelectorAll('.editor-tab').forEach(function(t) {
    t.classList.toggle('active', t.dataset.tab === tab);
  });
  const overrides = loadCardOverrides();
  const content = document.getElementById('editor-content');
  content.innerHTML = '';
  // Filtrar cards según tab
  let filter;
  if (tab === 'unidades') {
    filter = function(c) { return c.type === 'Unidad'; };
  } else {
    filter = function(c) {
      return c.type === 'Estructura' || c.type === 'Estructura Principal';
    };
  }
  // Encabezado
  const header = document.createElement('div');
  header.className = 'editor-card-row';
  header.style.background = 'transparent';
  header.style.border = 'none';
  header.style.color = '#888';
  header.style.fontSize = '11px';
  header.style.textTransform = 'uppercase';
  header.style.letterSpacing = '0.5px';
  if (tab === 'unidades') {
    header.innerHTML =
      '<div>Carta</div>' +
      '<div style="text-align:center">HP</div>' +
      '<div style="text-align:center">Coste</div>' +
      '<div style="text-align:center">Defensa</div>' +
      '<div style="text-align:center">PA/turno</div>';
  } else {
    header.innerHTML =
      '<div>Carta</div>' +
      '<div style="text-align:center">HP</div>' +
      '<div style="text-align:center">Coste</div>' +
      '<div style="text-align:center">— (no aplica)</div>' +
      '<div style="text-align:center">PA/turno</div>';
  }
  content.appendChild(header);

  CARDS.filter(filter).forEach(function(card) {
    const row = document.createElement('div');
    row.className = 'editor-card-row';
    row.dataset.cardName = card.name;
    const orig = CARD_ORIGINALS[card.name] || {};
    const ov = overrides[card.name] || {};

    // Nombre + badge subtipo
    const nameDiv = document.createElement('div');
    nameDiv.className = 'card-name';
    let subtypeLabel = '';
    if (card.type === 'Estructura Principal') subtypeLabel = 'Castillo';
    else if (card.subtype) subtypeLabel = card.subtype;
    nameDiv.innerHTML = card.name +
      (subtypeLabel ? ' <span class="subtype-badge">' + subtypeLabel + '</span>' : '');
    row.appendChild(nameDiv);

    function mkField(key, currentVal, origVal) {
      const f = document.createElement('div');
      f.className = 'editor-field';
      const inp = document.createElement('input');
      inp.type = 'number';
      inp.min = 0;
      inp.value = currentVal;
      inp.dataset.key = key;
      inp.dataset.cardName = card.name;
      if (currentVal !== origVal) inp.classList.add('modified');
      inp.addEventListener('input', function() {
        const v = parseInt(inp.value, 10);
        if (isFinite(v) && v !== origVal) inp.classList.add('modified');
        else inp.classList.remove('modified');
      });
      f.appendChild(inp);
      return f;
    }
    function mkDisabled() {
      const d = document.createElement('div');
      d.className = 'editor-field-disabled';
      d.textContent = '—';
      return d;
    }

    if (tab === 'unidades') {
      // HP, coste, def. PA/turno deshabilitado (las unidades no generan PA)
      row.appendChild(mkField('hp', ov.hp !== undefined ? ov.hp : card.hp, orig.hp));
      row.appendChild(mkField('cost', ov.cost !== undefined ? ov.cost : card.cost, orig.cost));
      row.appendChild(mkField('def', ov.def !== undefined ? ov.def : card.def, orig.def));
      row.appendChild(mkDisabled());
    } else {
      // HP, coste, ---, PA/turno
      row.appendChild(mkField('hp', ov.hp !== undefined ? ov.hp : card.hp, orig.hp));
      row.appendChild(mkField('cost', ov.cost !== undefined ? ov.cost : card.cost, orig.cost));
      row.appendChild(mkDisabled());
      row.appendChild(mkField('paT', ov.paT !== undefined ? ov.paT : card.paT, orig.paT));
    }
    content.appendChild(row);
  });
}

function collectEditorChanges() {
  const overrides = {};
  document.querySelectorAll('#editor-content input[type=number]').forEach(function(inp) {
    const v = parseInt(inp.value, 10);
    if (!isFinite(v) || v < 0) return;
    const name = inp.dataset.cardName;
    const key = inp.dataset.key;
    const orig = CARD_ORIGINALS[name] || {};
    if (v === orig[key]) return; // sin cambio respecto al original, no guardar
    if (!overrides[name]) overrides[name] = {};
    overrides[name][key] = v;
  });
  return overrides;
}

function saveEditorAndApply() {
  // Mezclar con overrides existentes de OTRA pestaña (no perderlos al guardar solo una)
  const existing = loadCardOverrides();
  const fromUI = collectEditorChanges();
  // Solo actualizamos las cartas que aparecen en la UI actual
  document.querySelectorAll('#editor-content input[type=number]').forEach(function(inp) {
    const name = inp.dataset.cardName;
    if (!existing[name]) return;
    // Para cada llave editada en la UI, sobrescribir; las que no, mantener
  });
  // Estrategia simple: para cada carta editada en la UI actual, reemplazar su entry
  // Otras cartas (que no están en esta pestaña) se preservan
  const merged = Object.assign({}, existing);
  const editedNames = new Set();
  document.querySelectorAll('#editor-content input[type=number]').forEach(function(inp) {
    editedNames.add(inp.dataset.cardName);
  });
  editedNames.forEach(function(n) {
    if (fromUI[n]) merged[n] = fromUI[n];
    else delete merged[n]; // ningún cambio respecto al original
  });
  saveCardOverrides(merged);
  // Re-render para mostrar los modificados
  renderEditorTab(_editorCurrentTab);
  showToast('Cambios guardados. Inicia una partida nueva para aplicarlos.', 'success');
}

function resetEditor() {
  if (!confirm('¿Restaurar TODOS los valores a los originales? Esto borra todos tus ajustes.')) return;
  localStorage.removeItem(EDITOR_STORAGE_KEY);
  renderEditorTab(_editorCurrentTab);
  showToast('Valores originales restaurados', 'success');
}

// Wire up del editor (después de DOMContentLoaded ya que el HTML está siempre presente)
document.getElementById('editor-close').addEventListener('click', closeEditor);
document.getElementById('editor-save').addEventListener('click', saveEditorAndApply);
document.getElementById('editor-reset').addEventListener('click', resetEditor);
document.querySelectorAll('.editor-tab').forEach(function(t) {
  t.addEventListener('click', function() {
    renderEditorTab(t.dataset.tab);
  });
});
// Cerrar con ESC o click en overlay
document.getElementById('editor-overlay').addEventListener('click', function(e) {
  if (e.target.id === 'editor-overlay') closeEditor();
});
document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape' && document.getElementById('editor-overlay').classList.contains('show')) {
    closeEditor();
  }
});

